CREATE OR REPLACE TABLE `msklad-bi-prod.marts.gmroi_by_folder` AS SELECT period_days, COALESCE(product_folder, "Без категории") AS product_folder, COUNT(DISTINCT product_id) AS product_count, ROUND(SUM(revenue_kgs),2) AS revenue_kgs, ROUND(SUM(cogs_kgs),2) AS cogs_kgs, ROUND(SUM(gross_profit_kgs),2) AS gross_profit_kgs, ROUND(SUM(avg_inventory_kgs),2) AS total_avg_inventory_kgs, ROUND(SAFE_DIVIDE(SUM(gross_profit_kgs),NULLIF(SUM(avg_inventory_kgs),0))*(365.0/period_days),2) AS gmroi_weighted, ROUND(SUM(gross_profit_kgs)/MAX(rate_kgs_per_usd),2) AS gross_profit_usd, ROUND(SUM(avg_inventory_kgs)/MAX(rate_kgs_per_usd),2) AS avg_inventory_usd, COUNTIF(is_inventory_missing) AS products_no_inventory, COUNTIF(is_cogs_zero) AS products_no_cogs, MAX(rate_kgs_per_usd) AS rate_kgs_per_usd, CURRENT_TIMESTAMP() AS _mart_refreshed_at FROM `msklad-bi-prod.marts.gmroi` GROUP BY period_days, product_folder
